		maxBit++
	}
	if maxBit < 1 {
		maxBit = 1
	}

	ans := 0
	for b := maxBit; b >= 0; b-- {
		kCandidate := ans | (1 << b)
		if check(arr, kCandidate) {
			ans = kCandidate
		}
	}
	return int64(ans)
