	n := len(nums)
	dsu := NewDSU(n)
	maskRep := make([]int, 1<<18)
	for i := range maskRep {
		maskRep[i] = -1
	}
	hasZero := false

	for i := 0; i < n; i++ {
		if (nums[i] & k) != k {
			if nums[i] != i {
				return false
			}
		} else {
			x := nums[i] & (^k)
			if x == 0 {
				hasZero = true
				if maskRep[0] != -1 {
					dsu.Union(i, maskRep[0])
				} else {
					maskRep[0] = i
				}
			} else {
				if maskRep[x] != -1 {
					dsu.Union(i, maskRep[x])
				} else {
					maskRep[x] = i
				}
				for j := x; j > 0; j = (j - 1) & x {
					if maskRep[j] != -1 {
						dsu.Union(i, maskRep[j])
					}
				}
				if hasZero {
					dsu.Union(i, maskRep[0])
				}
			}
		}
	}

	compToIndices := make(map[int][]int)
	for i := 0; i < n; i++ {
