		root := dsu.Find(i)
		compToIndices[root] = append(compToIndices[root], i)
	}

	for root, indices := range compToIndices {
		vals := make([]int, 0, len(indices))
		expectedIndices := make([]int, 0, len(indices))
		for _, idx := range indices {
			vals = append(vals, nums[idx])
			expectedIndices = append(expectedIndices, idx)
		}
